package ql.src.org.apache.hadoop.hive.ql.plan;

@ Explain ( displayName = "PTF Operator" ) public class PTFDesc extends AbstractOperatorDesc { private static final long serialVersionUID = 1L ; @ SuppressWarnings ( "unused" ) private static final Log LOG = LogFactory . getLog ( PTFDesc . class . getName ( ) ) ; PartitionedTableFunctionDef funcDef ; LeadLagInfo llInfo ; boolean isMapSide = false ; transient HiveConf cfg ; static { PTFUtils . makeTransient ( PTFDesc . class , "llInfo" ) ; PTFUtils . makeTransient ( PTFDesc . class , "cfg" ) ; } public PartitionedTableFunctionDef getFuncDef ( ) { return funcDef ; } public void setFuncDef ( PartitionedTableFunctionDef funcDef ) { this . funcDef = funcDef ; } public PartitionedTableFunctionDef getStartOfChain ( ) { return funcDef == null ? null : funcDef . getStartOfChain ( ) ; } public LeadLagInfo getLlInfo ( ) { return llInfo ; } public void setLlInfo ( LeadLagInfo llInfo ) { this . llInfo = llInfo ; } public boolean forWindowing ( ) { return funcDef != null && ( funcDef instanceof WindowTableFunctionDef ) ; } public boolean isMapSide ( ) { return isMapSide ; } public void setMapSide ( boolean isMapSide ) { this . isMapSide = isMapSide ; } public HiveConf getCfg ( ) { return cfg ; } public void setCfg ( HiveConf cfg ) { this . cfg = cfg ; } }